// Copyright (c) HashiCorp, Inc.
// SPDX-License-Identifier: BUSL-1.1

package format

import (
	"bytes"
	"fmt"
	"sort"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
	"github.com/hashicorp/terraform/internal/states"
)

// CompactDiffFormatter formats a plan as a concise summary of resource changes,
// showing only resource-level changes without attribute-level detail.
type CompactDiffFormatter struct{}

// Format returns a formatted string representation of the changes in the plan,
// grouped by action type with summary counts.
func (c *CompactDiffFormatter) Format(plan *plans.Plan, schemas *schemarepo.Schemas) string {
	if plan == nil || plan.Changes == nil {
		return ""
	}

	var buf bytes.Buffer

	// Group resources by action
	actionGroups := make(map[plans.Action][]*plans.ResourceInstanceChangeSrc)
	for _, rc := range plan.Changes.Resources {
		// Skip deposed objects and no-op changes
		if rc.DeposedKey != states.NotDeposed || rc.Action == plans.NoOp {
			continue
		}

		actionGroups[rc.Action] = append(actionGroups[rc.Action], rc)
	}

	// Define the order in which actions should be displayed
	actionOrder := []plans.Action{
		plans.Create,
		plans.Update,
		plans.DeleteThenCreate,
		plans.CreateThenDelete,
		plans.Delete,
		plans.Read,
		plans.Forget,
		plans.CreateThenForget,
		plans.Open,
		plans.Renew,
		plans.Close,
	}

	// Counters for summary
	var totalCount int

	// Format each action group
	for _, action := range actionOrder {
		resources, ok := actionGroups[action]
		if !ok || len(resources) == 0 {
			continue
		}

		// Sort resources by address for consistent output
		sort.Slice(resources, func(i, j int) bool {
			return resources[i].Addr.String() < resources[j].Addr.String()
		})

		// Write action section
		actionLabel := c.getActionLabel(action)
		buf.WriteString(fmt.Sprintf("%s:\n", actionLabel))

		for _, rc := range resources {
			// Format: "  resource_type.name"
			buf.WriteString(fmt.Sprintf("  %s\n", c.formatResourceAddress(rc.Addr)))
			totalCount++
		}

		buf.WriteString("\n")
	}

	// Write summary
	if totalCount > 0 {
		buf.WriteString(fmt.Sprintf("Summary: %d resource(s) will be changed\n", totalCount))
	} else {
		buf.WriteString("No changes planned\n")
	}

	return buf.String()
}

// getActionLabel returns a human-readable label for an action
func (c *CompactDiffFormatter) getActionLabel(action plans.Action) string {
	switch action {
	case plans.Create:
		return "Create"
	case plans.Update:
		return "Update"
	case plans.Delete:
		return "Delete"
	case plans.DeleteThenCreate:
		return "Replace (delete then create)"
	case plans.CreateThenDelete:
		return "Replace (create then delete)"
	case plans.Read:
		return "Read"
	case plans.Forget:
		return "Forget"
	case plans.CreateThenForget:
		return "Create then forget"
	case plans.Open:
		return "Open"
	case plans.Renew:
		return "Renew"
	case plans.Close:
		return "Close"
	default:
		return "Unknown"
	}
}

// formatResourceAddress returns a formatted resource address string
func (c *CompactDiffFormatter) formatResourceAddress(addr addrs.AbsResourceInstance) string {
	// Format: [module.path.]resource_type.name[instance_key]
	var buf bytes.Buffer

	// Add module path if not root
	if !addr.Module.IsRoot() {
		buf.WriteString(addr.Module.String())
		buf.WriteString(".")
	}

