func (c *CompactDiffFormatter) formatResourceAddress(addr addrs.AbsResourceInstance) string {
	// Format: [module.path.]resource_type.name[instance_key] or [module.path.]data.resource_type.name[instance_key]
	var buf bytes.Buffer

	// Add module path if not root
	if !addr.Module.IsRoot() {
		buf.WriteString(addr.Module.String())
		buf.WriteString(".")
	}

	// Add resource prefix for data sources
	if addr.Resource.Resource.Mode == addrs.DataResourceMode {
		buf.WriteString("data.")
	}

	// Add resource type and name
	buf.WriteString(addr.Resource.Resource.Type)
	buf.WriteString(".")
	buf.WriteString(addr.Resource.Resource.Name)

	// Add instance key if present
	if addr.Resource.Key != nil {
		buf.WriteString("[")
		buf.WriteString(addr.Resource.Key.String())
		buf.WriteString("]")
	}

	return buf.String()
}

